#define IN_RANGE(x, min, max) ((x) >= (min) && (x) <= (max))
#define CLAMP_RANGE(x, min, max) ((x) < (min) ? (min) : ((x) > (max) ? (max) : (x)))

__kernel void hotspot(
    int iteration,
    __global float *power,
    __global float *temp_src,
    __global float *temp_dst,
    int grid_cols,
    int grid_rows,
    int border_cols,
    int border_rows,
    float Cap,
    float Rx,
    float Ry,
    float Rz,
    float step)
{
    __local float temp_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float power_on_cuda[BLOCK_SIZE][BLOCK_SIZE];
    __local float temp_t[BLOCK_SIZE][BLOCK_SIZE];

    int tx = get_local_id(0);
    int ty = get_local_id(1);

    int bx = get_group_id(0);
    int by = get_group_id(1);

    int small_block_cols = BLOCK_SIZE - iteration * 2;
    int small_block_rows = BLOCK_SIZE - iteration * 2;

    int blk_x = small_block_cols * bx - border_cols;
    int blk_y = small_block_rows * by - border_rows;

    int xidx = blk_x + tx;
    int yidx = blk_y + ty;

    int index = yidx * grid_cols + xidx;

    int valid = IN_RANGE(xidx, 0, grid_cols - 1) && IN_RANGE(yidx, 0, grid_rows - 1);

    if (valid) {
        temp_on_cuda[ty][tx] = temp_src[index];
        power_on_cuda[ty][tx] = power[index];
    } else {
        temp_on_cuda[ty][tx] = 0.0f;
        power_on_cuda[ty][tx] = 0.0f;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    float step_div_Cap = step / Cap;

    for (int i = 0; i < iteration; i++) {
        int computed = IN_RANGE(tx, i + 1, BLOCK_SIZE - i - 2) &&
                       IN_RANGE(ty, i + 1, BLOCK_SIZE - i - 2) &&
                       IN_RANGE(xidx, 0, grid_cols - 1) &&
                       IN_RANGE(yidx, 0, grid_rows - 1);

        if (computed) {
            float center = temp_on_cuda[ty][tx];

            float north = (yidx == 0) ? center : temp_on_cuda[ty - 1][tx];
            float south = (yidx == grid_rows - 1) ? center : temp_on_cuda[ty + 1][tx];
            float west  = (xidx == 0) ? center : temp_on_cuda[ty][tx - 1];
            float east  = (xidx == grid_cols - 1) ? center : temp_on_cuda[ty][tx + 1];

            temp_t[ty][tx] = center + step_div_Cap *
                (power_on_cuda[ty][tx] +
                 (south + north - 2.0f * center) / Ry +
                 (east + west - 2.0f * center) / Rx +
                 (80.0f - center) / Rz);
        }

        barrier(CLK_LOCAL_MEM_FENCE);

        if (computed) {
            temp_on_cuda[ty][tx] = temp_t[ty][tx];
        }

        barrier(CLK_LOCAL_MEM_FENCE);
    }

    int write_valid = IN_RANGE(tx, border_cols, BLOCK_SIZE - border_cols - 1) &&
                      IN_RANGE(ty, border_rows, BLOCK_SIZE - border_rows - 1) &&
                      IN_RANGE(xidx, 0, grid_cols - 1) &&
                      IN_RANGE(yidx, 0, grid_rows - 1);

    if (write_valid) {
        temp_dst[index] = temp_on_cuda[ty][tx];
    }
}
